 70→        }
 71→      }
 72→      // All retries exhausted — don't cache a wrong port. Throw so TanStack Query
 73→      // retries the entire fetch later, giving the backend more time to start.
 74→      console.error("[API] getBackendPort failed after retries — backend may not have started");
 75→      throw new Error("Backend port not available after retries");
 76→    }
 77→
 78→    // 3. Dev mode: fetch port from Vite middleware (Electron writes it to temp file).
 79→    // This enables Chrome tabs at localhost:1420 to work during `bun run dev`.
 80→    if (import.meta.env.DEV) {
 81→      try {
 82→        const res = await fetch("/__backend_port");
 83→        if (res.ok) {
 84→          const data = await res.json();
 85→          if (data.port && typeof data.port === "number") {
 86→            if (import.meta.env.DEV)
 87→              console.log(`[API] Using backend port from dev server: ${data.port}`);
 88→            cachedPort = data.port;
 89→            return data.port;
 90→          }
 91→        }
 92→      } catch {
 93→        // Vite middleware not available (production or standalone web mode)
 94→      }
 95→    }
 96→
 97→    // 4. Last resort fallback
 98→    console.warn("[API] No port source available, falling back to default port 3333");
 99→    cachedPort = 3333;
100→    return 3333;
101→  })();
102→
103→  // Clear promise when done (success or failure)
104→  portPromise.finally(() => {
105→    portPromise = null;
106→  });
107→
108→  return portPromise;
109→}
110→
111→/**
112→ * Set the backend port directly and clear any in-flight resolution.
113→ * Called when the main process notifies the renderer of a backend restart
114→ * with a new port — the WebSocket reconnect loop will pick up the new port
115→ * on its next `getBackendPort()` call (which returns immediately from cache).
116→ */
117→export function setBackendPort(port: number): void {
118→  cachedPort = port;
119→  portPromise = null;
120→  if (import.meta.env.DEV) {
121→    console.log(`[API] Backend port updated to ${port} (backend restarted)`);
122→  }
123→}
