 10→import { track } from "@/platform/analytics";
 11→import type { Settings, MCPServer, Command, Agent } from "../types";
 12→
 13→/**
 14→ * Fetch all settings
 15→ */
 16→export function useSettings() {
 17→  return useQuery({
 18→    queryKey: queryKeys.settings.all,
 19→    queryFn: () => SettingsService.fetch(),
 20→    staleTime: 30000, // Cache for 30s (settings change less frequently)
 21→  });
 22→}
 23→
 24→/**
 25→ * Fetch MCP servers configuration
 26→ */
 27→export function useMCPServers() {
 28→  return useQuery({
 29→    queryKey: queryKeys.settings.mcpServers,
 30→    queryFn: () => SettingsService.fetchFileConfig<MCPServer[]>("mcp-servers"),
 31→    staleTime: 30000,
 32→  });
 33→}
 34→
 35→/**
 36→ * Fetch commands configuration
 37→ */
 38→export function useCommands() {
 39→  return useQuery({
 40→    queryKey: queryKeys.settings.commands,
 41→    queryFn: () => SettingsService.fetchFileConfig<Command[]>("commands"),
 42→    staleTime: 30000,
 43→  });
 44→}
 45→
 46→/**
 47→ * Fetch agents configuration
 48→ */
 49→export function useAgents() {
 50→  return useQuery({
 51→    queryKey: queryKeys.settings.agents,
 52→    queryFn: () => SettingsService.fetchFileConfig<Agent[]>("agents"),
 53→    staleTime: 30000,
 54→  });
 55→}
 56→
 57→/**
 58→ * Update settings mutation with optimistic update
 59→ */
 60→export function useUpdateSettings() {
 61→  const queryClient = useQueryClient();
 62→
 63→  return useMutation({
 64→    mutationFn: (settings: Partial<Settings>) => SettingsService.update(settings),
 65→
 66→    // Optimistic update: Apply settings immediately
 67→    onMutate: async (newSettings: Partial<Settings>) => {
 68→      await queryClient.cancelQueries({ queryKey: queryKeys.settings.all });
 69→
 70→      const previousSettings = queryClient.getQueryData<Settings>(queryKeys.settings.all);
 71→
 72→      queryClient.setQueryData<Settings>(queryKeys.settings.all, (old) => {
 73→        if (!old) return old;
 74→        return produce(old, (draft) => {
 75→          Object.assign(draft, newSettings);
 76→        });
 77→      });
 78→
 79→      return { previousSettings };
 80→    },
 81→
 82→    onError: (_err, _newSettings, context) => {
 83→      if (context?.previousSettings) {
 84→        queryClient.setQueryData(queryKeys.settings.all, context.previousSettings);
 85→      }
 86→    },
 87→
 88→    onSuccess: (_data, newSettings) => {
 89→      // Track each changed key. Only include value for safe enum-type settings
 90→      // (theme, provider). Never log API keys or free-text inputs.
 91→      const SAFE_VALUE_KEYS = new Set(["theme", "claude_provider"]);
 92→      for (const key of Object.keys(newSettings)) {
 93→        const value = SAFE_VALUE_KEYS.has(key)
 94→          ? String((newSettings as Record<string, unknown>)[key])
 95→          : undefined;
 96→        track("setting_changed", { key, value });
 97→      }
 98→    },
 99→
100→    onSettled: () => {
101→      queryClient.invalidateQueries({ queryKey: queryKeys.settings.all });
102→    },
103→  });
104→}
