  1→/**
  2→ * Backend Process Manager
  3→ *
  4→ * Spawns the Node.js backend as a child process.
  5→ * - Production: use the Electron binary with ELECTRON_RUN_AS_NODE=1.
  6→ * - Development: use the host Node runtime so native modules match the dev install ABI.
  7→ * Parses the dynamic port from stdout, generates an auth token, and handles
  8→ * exit/restart with exponential backoff.
  9→ *
 10→ * Uses child_process directly since we're already in Node.js.
 11→ */
 12→
 13→import { spawn, type ChildProcess } from "child_process";
 14→import { join } from "path";
 15→import { existsSync, writeFileSync } from "fs";
 16→import { app, BrowserWindow } from "electron";
 17→import crypto from "crypto";
 18→
 19→let backendProcess: ChildProcess | null = null;
 20→let isQuitting = false;
 21→let restartAttempt = 0;
 22→let restartTimer: ReturnType<typeof setTimeout> | null = null;
 23→const MAX_RESTART_ATTEMPTS = 5;
 24→const STARTUP_TIMEOUT_MS = 30_000;
 25→
 26→export async function spawnBackend(): Promise<{ port: number; authToken: string }> {
 27→  const authToken = crypto.randomBytes(24).toString("hex");
 28→  const projectRoot = join(__dirname, "../..");
 29→  const backendRuntime = app.isPackaged ? process.execPath : "node";
 30→
 31→  // Resolve backend entry point
 32→  // Production: bundled CJS file (no tsx dependency needed)
 33→  // Development: server.cjs bootstraps tsx for live TypeScript
 34→  const backendEntry = app.isPackaged
 35→    ? join(process.resourcesPath, "backend", "server.bundled.cjs")
 36→    : join(projectRoot, "apps/backend/server.cjs");
 37→
 38→  // Database path — prefer legacy location (com.opendevs.ide) if it exists,
 39→  // otherwise use Electron's userData dir (~/Library/Application Support/opendevs/).
 40→  const legacyDbPath = join(app.getPath("appData"), "com.opendevs.ide", "opendevs.db");
 41→  const electronDbPath = join(app.getPath("userData"), "opendevs.db");
 42→  const dbPath = existsSync(legacyDbPath) ? legacyDbPath : electronDbPath;
 43→
 44→  // Sidecar bundle path
 45→  const sidecarPath = app.isPackaged
 46→    ? join(process.resourcesPath, "bin", "index.bundled.cjs")
 47→    : join(projectRoot, "apps/sidecar/dist/index.bundled.cjs");
 48→
 49→  // Notebook server bundle path
 50→  const notebookPath = app.isPackaged
 51→    ? join(process.resourcesPath, "bin", "notebook-server.bundled.cjs")
 52→    : join(projectRoot, "packages/mcp-notebook/dist/notebook-server.bundled.cjs");
 53→
 54→  return new Promise((resolve, reject) => {
 55→    backendProcess = spawn(backendRuntime, [backendEntry], {
 56→      cwd: app.isPackaged ? process.resourcesPath : join(projectRoot, "apps/backend"),
 57→      env: {
 58→        ...process.env,
 59→        ...(app.isPackaged ? { ELECTRON_RUN_AS_NODE: "1" } : {}),
 60→        DATABASE_PATH: dbPath,
 61→        SIDECAR_BUNDLE_PATH: sidecarPath,
 62→        NOTEBOOK_SERVER_BUNDLE_PATH: notebookPath,
 63→        AUTH_TOKEN: authToken,
 64→        PORT: "0", // Dynamic port allocation
 65→      },
 66→      stdio: ["ignore", "pipe", "pipe"],
 67→    });
 68→
 69→    let resolved = false;
 70→    let stdoutBuffer = "";
 71→
 72→    // Parse port from stdout
 73→    backendProcess.stdout?.on("data", (data: Buffer) => {
 74→      stdoutBuffer += data.toString();
 75→      const lines = stdoutBuffer.split("\n");
 76→      stdoutBuffer = lines.pop() ?? ""; // Keep incomplete last line in buffer
 77→      for (const line of lines) {
 78→        const trimmed = line.trim();
 79→        if (!trimmed) continue;
 80→
 81→        // Log backend stdout in dev mode
 82→        if (!app.isPackaged) {
 83→          console.log("[backend]", trimmed);
 84→        }
 85→
 86→        // Match both formats: "[BACKEND_PORT]12345" (primary) and
 87→        // "Backend server started on port 12345" (legacy fallback).
 88→        const portMatch =
 89→          trimmed.match(/^\[BACKEND_PORT\](\d+)$/) ||
 90→          trimmed.match(/Backend server started on port (\d+)/);
 91→        if (portMatch && !resolved) {
 92→          resolved = true;
 93→          restartAttempt = 0;
 94→          const port = parseInt(portMatch[1], 10);
 95→
 96→          // Write port to temp file so Chrome tabs (without electronAPI) can discover it.
 97→          // The Vite dev server serves this via middleware in electron.vite.config.ts.
 98→          if (!app.isPackaged) {
 99→            try {
100→              const portFile = join(app.getPath("temp"), "opendevs-backend-port");
101→              writeFileSync(portFile, String(port));
102→            } catch {
103→              // Non-critical — only used for Chrome tab port discovery
104→            }
105→          }
106→
107→          resolve({ port, authToken });
108→        }
109→
110→        // Relay workspace init progress events to the renderer.
111→        // Backend emits: OPENDEVS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
112→        // We parse the JSON and forward it as an IPC event to the renderer.
113→        // SYNC: Event name must match shared/events.ts (AppEventMap["workspace:progress"])
114→        if (trimmed.startsWith("OPENDEVS_WORKSPACE_PROGRESS:")) {
115→          const jsonStr = trimmed.slice("OPENDEVS_WORKSPACE_PROGRESS:".length);
116→          try {
117→            const payload = JSON.parse(jsonStr);
118→            const win = BrowserWindow.getAllWindows()[0];
119→            if (win) {
120→              win.webContents.send("workspace:progress", payload);
121→            }
122→          } catch {
123→            // Ignore malformed progress lines
124→          }
125→        }
126→      }
127→    });
128→
129→    backendProcess.stderr?.on("data", (data: Buffer) => {
130→      console.error("[backend:stderr]", data.toString().trim());
131→    });
132→
133→    backendProcess.on("exit", (code, signal) => {
134→      console.log(`[backend] Exited with code=${code} signal=${signal}`);
135→      backendProcess = null;
136→
137→      if (!resolved) {
138→        reject(new Error(`Backend exited before starting (code=${code})`));
139→        return;
140→      }
141→
142→      // Restart with exponential backoff (unless app is quitting)
143→      if (!isQuitting && restartAttempt < MAX_RESTART_ATTEMPTS) {
144→        restartAttempt++;
145→        const delay = Math.min(1000 * Math.pow(2, restartAttempt - 1), 30_000);
146→        console.log(`[backend] Restart attempt ${restartAttempt} in ${delay}ms`);
147→        restartTimer = setTimeout(() => {
148→          restartTimer = null;
149→          spawnBackend()
150→            .then(({ port, authToken: newAuthToken }) => {
151→              // Update env vars so IPC handlers (native:getBackendPort) return the new port
152→              process.env.OPENDEVS_BACKEND_PORT = String(port);
153→              process.env.OPENDEVS_AUTH_TOKEN = newAuthToken;
154→
155→              // Notify all renderer windows so they can invalidate their cached port
156→              // and reconnect WebSocket to the new address.
157→              for (const win of BrowserWindow.getAllWindows()) {
158→                win.webContents.send("backend:port-changed", { port });
159→              }
160→              console.log(`[backend] Restarted on port ${port}, notified renderer`);
161→            })
162→            .catch((err) => {
163→              console.error("[backend] Restart failed:", err);
164→            });
165→        }, delay);
166→      }
167→    });
168→
169→    backendProcess.on("error", (err) => {
170→      console.error("[backend] Spawn error:", err);
171→      if (!resolved) {
172→        reject(err);
173→      }
174→    });
175→
176→    // Timeout if backend doesn't start
177→    setTimeout(() => {
178→      if (!resolved) {
179→        resolved = true;
180→        backendProcess?.kill("SIGTERM");
181→        reject(new Error(`Backend startup timeout (${STARTUP_TIMEOUT_MS}ms)`));
182→      }
183→    }, STARTUP_TIMEOUT_MS);
184→  });
185→}
186→
187→export function stopBackend(): void {
188→  isQuitting = true;
189→  if (restartTimer) {
190→    clearTimeout(restartTimer);
191→    restartTimer = null;
192→  }
193→  if (backendProcess) {
194→    backendProcess.kill("SIGTERM");
195→    // Force kill after 5s if graceful shutdown fails
196→    const forceTimer = setTimeout(() => {
197→      if (backendProcess) {
198→        backendProcess.kill("SIGKILL");
199→        backendProcess = null;
200→      }
201→    }, 5_000);
202→    backendProcess.on("exit", () => {
203→      clearTimeout(forceTimer);
204→      backendProcess = null;
205→    });
206→  }
207→}
208→

