 26→// The main window creates it with ?window=browser-detached in the URL.
 27→const isDetachedBrowser =
 28→  new URLSearchParams(window.location.search).get("window") === "browser-detached";
 29→
 30→/** Shared error handler for React error boundaries — reports + stores component stack. */
 31→function createBoundaryErrorHandler(source: string) {
 32→  return (error: unknown, info: ErrorInfo) => {
 33→    reportError(error, {
 34→      source,
 35→      extra: { componentStack: info.componentStack ?? undefined },
 36→    });
 37→    (window as { __APP_LAST_COMPONENT_STACK__?: string }).__APP_LAST_COMPONENT_STACK__ =
 38→      info.componentStack ?? undefined;
 39→  };
 40→}
 41→
 42→/**
 43→ * Gates between onboarding and the main app.
 44→ *
 45→ * When onboarding is active, ONLY OnboardingOverlay renders — no MainLayout,
 46→ * no sidebar, no workspace panels. This ensures the transparent window shows
 47→ * the desktop through the semi-transparent scrim, not the app's own UI.
 48→ */
 49→function AppContent({ reset }: { reset: () => void }) {
 50→  const auth = useAuth();
 51→  const settingsQuery = useSettings();
 52→  const windowShownRef = useRef(false);
 53→
 54→  // Request OS notification permission once on mount
 55→  useEffect(() => {
 56→    initNotifications();
 57→  }, []);
 58→
 59→  // Global listener: fire OS notifications for ALL session events when backgrounded
 60→  useGlobalSessionNotifications();
 61→
 62→  // Global listener: workspace init progress → invalidate queries on completion
 63→  useWorkspaceInitEvents();
 64→
 65→  // Global listener: WS query protocol → direct cache updates + invalidation dispatch
 66→  useQueryProtocol();
 67→
 68→  // Global listener: backend restart → update cached port + force WS reconnect
 69→  useBackendRestart();
 70→
 71→  // Sync PostHog opt-in/out state with analytics_enabled setting
 72→  useAnalyticsConsent();
 73→
 74→  // Auto-update: check on launch + every 5 min, show toast when ready
 75→  const autoUpdate = useAutoUpdate();
 76→  useUpdateToast(autoUpdate);
 77→
 78→  const showOnboarding = !settingsQuery.isError && !settingsQuery.data?.onboarding_completed;
 79→
 80→  // Boot diagnostics — trace the window-show flow so we can see what's blocking
 81→  useEffect(() => {
 82→    if (import.meta.env.DEV) {
 83→      console.log("[App] AppContent mount — auth:", {
 84→        isLoading: auth.isLoading,
 85→        isAuthenticated: auth.isAuthenticated,
 86→      });
 87→      console.log("[App] AppContent mount — settings:", {
 88→        isLoading: settingsQuery.isLoading,
 89→        isError: settingsQuery.isError,
 90→        hasData: !!settingsQuery.data,
 91→        onboardingCompleted: settingsQuery.data?.onboarding_completed,
 92→        showOnboarding,
 93→      });
 94→    }
 95→  }, [
 96→    auth.isLoading,
 97→    auth.isAuthenticated,
 98→    settingsQuery.isLoading,
 99→    settingsQuery.isError,
100→    settingsQuery.data,
101→    showOnboarding,
102→  ]);
103→
104→  // Show the main window whenever we transition OUT of onboarding.
105→  // Covers both first launch (window starts hidden, show: false in createWindow)
106→  // and replay-onboarding (exit_onboarding_mode hides the window).
107→  useEffect(() => {
108→    if (settingsQuery.isLoading) return;
109→    if (showOnboarding) {
110→      // Entering onboarding — reset so we re-show when it completes
111→      windowShownRef.current = false;
112→      return;
113→    }
114→    if (windowShownRef.current) return;
115→    if (isElectronEnv) invoke("show_main_window").catch(console.error);
116→    windowShownRef.current = true;
117→  }, [settingsQuery.isLoading, showOnboarding]);
118→
119→  // Remote browser auth gate: show pairing page if not authenticated
120→  if (auth.isLoading) return null;
121→  if (!auth.isAuthenticated) return <PairGatePage onPaired={auth.onPaired} />;
122→
123→  // While settings load, render nothing — window is hidden anyway
124→  if (settingsQuery.isLoading) return null;
125→
126→  // Backend unreachable — show error instead of white screen.
127→  // This happens when opening localhost:1420 in Chrome during `bun run dev`
128→  // (Electron mode) without VITE_BACKEND_PORT, or when the backend crashed.
129→  if (settingsQuery.isError && !settingsQuery.data) {
130→    return (
131→      <div className="bg-background flex h-screen items-center justify-center">
132→        <div className="max-w-md space-y-4 text-center">
133→          <h1 className="text-foreground text-xl font-semibold">Cannot connect to backend</h1>
134→          <p className="text-muted-foreground text-sm">
135→            {isElectronEnv
136→              ? "The backend server failed to start. Check the terminal for errors."
137→              : "Run `bun run dev:web` for browser development, or use the Electron desktop app (`bun run dev`)."}
138→          </p>
139→          <button
140→            type="button"
141→            onClick={() => settingsQuery.refetch()}
142→            className="bg-primary text-primary-foreground hover:bg-primary/90 rounded-lg px-4 py-2 text-sm font-medium"
143→          >
144→            Retry
145→          </button>
146→        </div>
147→      </div>
148→    );
149→  }
150→
151→  if (showOnboarding) {
152→    return <OnboardingOverlay />;
153→  }
154→
155→  return (
156→    <UpdateProvider value={autoUpdate}>
157→      <BrowserRouter>
158→        <Routes>
159→          <Route
160→            path="/"
161→            element={
162→              <ErrorBoundary
163→                FallbackComponent={DashboardError}
164→                onReset={reset}
165→                onError={createBoundaryErrorHandler("react.error-boundary.root")}
166→              >
167→                <MainLayout />
168→              </ErrorBoundary>
169→            }
170→          />
171→        </Routes>
172→      </BrowserRouter>
173→      <Toaster />
174→    </UpdateProvider>
175→  );
176→}
177→
178→/**
179→ * Safety net: ensure the window always becomes visible.
180→ *
181→ * The main window starts hidden (show: false in createWindow) to avoid
182→ * a flash before onboarding/content is ready. Normally the frontend calls
183→ * show_main_window or enter_onboarding_mode within ~1-2s. But if anything
184→ * goes wrong (settings fetch hangs, unexpected error, hook crash), the window
185→ * stays hidden and the user sees only a dock icon with no window.
186→ *
187→ * This timeout guarantees the window appears within WINDOW_SHOW_TIMEOUT_MS,
188→ * no matter what. It's a last resort — the normal flow or ErrorFallback
189→ * should show the window sooner.
190→ */
191→const WINDOW_SHOW_TIMEOUT_MS = 5_000;
192→
193→function useWindowShowSafetyNet() {
194→  const shownRef = useRef(false);
195→  useEffect(() => {
196→    if (shownRef.current || !isElectronEnv) return;
197→    const timer = setTimeout(() => {
198→      if (!shownRef.current) {
199→        shownRef.current = true;
200→        console.warn("[App] Safety net: force-showing window after timeout");
201→        invoke("show_main_window").catch(console.error);
202→      }
203→    }, WINDOW_SHOW_TIMEOUT_MS);
204→    return () => clearTimeout(timer);
205→  }, []);
206→}
207→
208→function App() {
209→  // Safety net — force-show window if nothing else does within 5s
210→  useWindowShowSafetyNet();
211→
212→  const content = isDetachedBrowser ? (
213→    // Detached browser window: minimal shell with just the browser panel
214→    <QueryClientProvider>
215→      <ThemeProvider>
216→        <DetachedBrowserWindow />
217→      </ThemeProvider>
218→    </QueryClientProvider>
219→  ) : (
220→    <QueryClientProvider>
221→      <QueryErrorResetBoundary>
222→        {({ reset }) => (
223→          <ErrorBoundary
224→            FallbackComponent={ErrorFallback}
225→            onReset={reset}
226→            onError={createBoundaryErrorHandler("react.error-boundary")}
227→          >
228→            <ThemeProvider>
229→              <AppContent reset={reset} />
230→            </ThemeProvider>
231→          </ErrorBoundary>
232→        )}
233→      </QueryErrorResetBoundary>
234→    </QueryClientProvider>
235→  );
236→
237→  return (
238→    <LazyMotion features={domAnimation} strict>
239→      {content}
240→    </LazyMotion>
241→  );
242→}
243→
244→export default App;
245→

