 2→ * Settings Service
 3→ * API methods for settings management
 4→ */
 5→
 6→import { apiClient } from "@/shared/api/client";
 7→import type { Settings } from "../types";
 8→
 9→export const SettingsService = {
10→  /**
11→   * Fetch all settings
12→   */
13→  fetch: async (): Promise<Settings> => {
14→    return apiClient.get<Settings>("/settings");
15→  },
16→
17→  /**
18→   * Update a single setting. The mutation always passes one key at a time
19→   * as Partial<Settings>, but the backend expects { key, value } format.
20→   */
21→  update: async (settings: Partial<Settings>): Promise<Settings> => {
22→    const [key, value] = Object.entries(settings)[0];
23→    return apiClient.post<Settings>("/settings", { key, value });
24→  },
25→
26→  /**
27→   * Fetch file-based configs (MCP servers, commands, agents, hooks)
28→   */
29→  fetchFileConfig: async <T>(type: string): Promise<T> => {
