  1→/**
  2→ * Base API Client
  3→ * Handles HTTP requests with proper error handling and type safety
  4→ *
  5→ * Now supports dynamic port allocation.
  6→ * Attaches Bearer token for remote (non-localhost) browser clients.
  7→ */
  8→
  9→import { getBaseURL } from "../config/api.config";
 10→import { getStoredToken, needsRemoteAuth } from "@/features/auth";
 11→import type { ApiError } from "../types";
 12→
 13→/** Request timeout in milliseconds. */
 14→const REQUEST_TIMEOUT = 30_000;
 15→
 16→class ApiClient {
 17→  private timeout: number;
 18→
 19→  constructor(timeout: number = REQUEST_TIMEOUT) {
 20→    this.timeout = timeout;
 21→  }
 22→
 23→  /**
 24→   * Generic GET request
 25→   */
 26→  async get<T>(endpoint: string): Promise<T> {
 27→    return this.request<T>(endpoint, { method: "GET" });
 28→  }
 29→
 30→  /**
 31→   * Generic POST request
 32→   */
 33→  async post<T>(endpoint: string, data?: any): Promise<T> {
 34→    return this.request<T>(endpoint, {
 35→      method: "POST",
 36→      headers: { "Content-Type": "application/json" },
 37→      body: data ? JSON.stringify(data) : undefined,
 38→    });
 39→  }
 40→
 41→  /**
 42→   * Generic PUT request
 43→   */
 44→  async put<T>(endpoint: string, data?: any): Promise<T> {
 45→    return this.request<T>(endpoint, {
 46→      method: "PUT",
 47→      headers: { "Content-Type": "application/json" },
 48→      body: data ? JSON.stringify(data) : undefined,
 49→    });
 50→  }
 51→
 52→  /**
 53→   * Generic PATCH request
 54→   */
 55→  async patch<T>(endpoint: string, data: any): Promise<T> {
 56→    return this.request<T>(endpoint, {
 57→      method: "PATCH",
 58→      headers: { "Content-Type": "application/json" },
 59→      body: JSON.stringify(data),
 60→    });
 61→  }
 62→
 63→  /**
 64→   * Generic DELETE request
 65→   */
 66→  async delete<T>(endpoint: string): Promise<T> {
 67→    return this.request<T>(endpoint, { method: "DELETE" });
 68→  }
 69→
 70→  /**
 71→   * Core request method with timeout and error handling.
 72→   * Attaches Authorization header for remote browser clients.
 73→   */
 74→  private async request<T>(endpoint: string, options: RequestInit): Promise<T> {
 75→    const baseURL = await getBaseURL();
 76→    const url = `${baseURL}${endpoint}`;
 77→    const controller = new AbortController();
 78→    const timeoutId = setTimeout(() => controller.abort(), this.timeout);
 79→
 80→    // Attach Bearer token for remote (non-localhost) browser sessions
 81→    const headers = new Headers(options.headers);
 82→    if (needsRemoteAuth()) {
 83→      const token = getStoredToken();
 84→      if (token) {
 85→        headers.set("Authorization", `Bearer ${token}`);
 86→      }
 87→    }
 88→
 89→    try {
 90→      const response = await fetch(url, {
 91→        ...options,
 92→        headers,
 93→        signal: controller.signal,
 94→      });
 95→
 96→      clearTimeout(timeoutId);
 97→
 98→      if (!response.ok) {
 99→        const error: ApiError = {
100→          status: response.status,
101→          message: response.statusText,
102→        };
103→
104→        try {
105→          const errorData = await response.json();
106→          error.details = errorData;
107→          error.message = errorData.error || errorData.message || error.message;
108→        } catch {
109→          // Response is not JSON
110→        }
111→
112→        throw error;
113→      }
114→
115→      // Handle empty responses
116→      const contentType = response.headers.get("content-type");
117→      if (!contentType || !contentType.includes("application/json")) {
118→        return null as T;
119→      }
120→
121→      return await response.json();
122→    } catch (error) {
123→      clearTimeout(timeoutId);
124→
125→      if (error instanceof Error) {
126→        if (error.name === "AbortError") {
127→          throw {
128→            status: 408,
129→            message: "Request timeout",
130→            details: error,
131→          } as ApiError;
132→        }
133→        throw {
134→          status: 0,
135→          message: error.message,
136→          details: error,
137→        } as ApiError;
138→      }
139→
140→      throw error;
141→    }
142→  }
143→}
144→
145→// Export singleton instance
146→export const apiClient = new ApiClient();
147→

  1→/**
  2→ * API Configuration
  3→ * Central configuration for API endpoints and settings
  4→ *
  5→ * Port resolution:
  6→ * - Electron app: Uses preload bridge via window.electronAPI.getBackendPort()
  7→ * - Web dev: Uses VITE_BACKEND_PORT environment variable from dev.sh
  8→ */
  9→
 10→// Import directly from the source module (not the barrel) to avoid circular
 11→// dependency: client.ts → api.config.ts → platform/electron/index.ts → ... → client.ts
 12→import { isElectronEnv } from "@/platform/electron/invoke";
 13→
 14→let cachedPort: number | null = null;
 15→let portPromise: Promise<number> | null = null;
 16→
 17→// IPC retry config for backend port resolution.
 18→// The backend may not have emitted its [BACKEND_PORT] marker yet during early
 19→// startup — the main process waits for it before returning the port.
 20→// 30 attempts × 200ms = 6s covers the startup timeout with margin.
 21→const PORT_MAX_RETRIES = 30;
 22→const PORT_RETRY_DELAY_MS = 200;
 23→
 24→/**
 25→ * Get the backend port (cached after first call).
 26→ *
 27→ * In Electron mode, retries the IPC call with backoff because the backend may
 28→ * still be starting when the renderer first loads. Without retries, a single
 29→ * failed invoke permanently caches port 3333, causing all API requests to
 30→ * hit the wrong port and leaving the window hidden.
 31→ */
 32→export async function getBackendPort(): Promise<number> {
 33→  if (cachedPort !== null) {
 34→    return cachedPort;
 35→  }
 36→
 37→  // If there's already a pending request, return it
 38→  if (portPromise !== null) {
 39→    return portPromise;
 40→  }
 41→
 42→  portPromise = (async () => {
 43→    // 1. Check if running in web dev mode with dynamic port
 44→    if (import.meta.env.VITE_BACKEND_PORT) {
 45→      const port = parseInt(import.meta.env.VITE_BACKEND_PORT as string, 10);
 46→      if (!isNaN(port)) {
 47→        if (import.meta.env.DEV) console.log(`[API] Using web dev backend port: ${port}`);
 48→        cachedPort = port;
 49→        return port;
 50→      }
 51→    }
 52→
 53→    // 2. Electron: use the dedicated preload API (bypasses generic invoke bridge).
 54→    // The backend is spawned by the main process before the window is created,
 55→    // so the port should be available immediately via native:getBackendPort.
 56→    // Retry with backoff for the rare case where the renderer loads before the
 57→    // backend has emitted its [BACKEND_PORT] marker.
 58→    if (isElectronEnv) {
 59→      for (let attempt = 0; attempt < PORT_MAX_RETRIES; attempt++) {
 60→        try {
 61→          const port = await window.electronAPI!.getBackendPort();
 62→          if (import.meta.env.DEV)
 63→            console.log(`[API] Using Electron backend port: ${port} (attempt ${attempt + 1})`);
 64→          cachedPort = port;
 65→          return port;
 66→        } catch {
 67→          if (attempt < PORT_MAX_RETRIES - 1) {
 68→            await new Promise((resolve) => setTimeout(resolve, PORT_RETRY_DELAY_MS));
 69→          }
 70→        }
 71→      }
 72→      // All retries exhausted — don't cache a wrong port. Throw so TanStack Query
 73→      // retries the entire fetch later, giving the backend more time to start.
 74→      console.error("[API] getBackendPort failed after retries — backend may not have started");
 75→      throw new Error("Backend port not available after retries");
 76→    }
 77→
 78→    // 3. Dev mode: fetch port from Vite middleware (Electron writes it to temp file).
 79→    // This enables Chrome tabs at localhost:1420 to work during `bun run dev`.
 80→    if (import.meta.env.DEV) {
 81→      try {
 82→        const res = await fetch("/__backend_port");
 83→        if (res.ok) {
 84→          const data = await res.json();
 85→          if (data.port && typeof data.port === "number") {
 86→            if (import.meta.env.DEV)
 87→              console.log(`[API] Using backend port from dev server: ${data.port}`);
 88→            cachedPort = data.port;
 89→            return data.port;
 90→          }
 91→        }
 92→      } catch {
 93→        // Vite middleware not available (production or standalone web mode)
 94→      }
 95→    }
 96→
 97→    // 4. Last resort fallback
 98→    console.warn("[API] No port source available, falling back to default port 3333");
 99→    cachedPort = 3333;
100→    return 3333;
101→  })();
102→
103→  // Clear promise when done (success or failure)
104→  portPromise.finally(() => {
105→    portPromise = null;
106→  });
107→
108→  return portPromise;
109→}
110→
111→/**
112→ * Set the backend port directly and clear any in-flight resolution.
113→ * Called when the main process notifies the renderer of a backend restart
114→ * with a new port — the WebSocket reconnect loop will pick up the new port
115→ * on its next `getBackendPort()` call (which returns immediately from cache).
116→ */
117→export function setBackendPort(port: number): void {
118→  cachedPort = port;
119→  portPromise = null;
120→  if (import.meta.env.DEV) {
121→    console.log(`[API] Backend port updated to ${port} (backend restarted)`);
122→  }
123→}
124→
125→/**
126→ * Get the backend origin URL (e.g. http://localhost:12345)
127→ */
128→export async function getBackendUrl(): Promise<string> {
129→  const port = await getBackendPort();
130→  return `http://localhost:${port}`;
131→}
132→
133→/**
134→ * Get the base URL for API requests (async)
135→ */
136→export async function getBaseURL(): Promise<string> {
137→  const port = await getBackendPort();
138→  return `http://localhost:${port}/api`;
139→}
